dataQuery.sqlStatement:
SELECT hou.name operatingunit, asu.vendor_name supname, asu.segment1 supnum, assa.vendor_site_code suppliersite, aia.invoice_num invoice_num
FROM ap_invoices_all aia, hr_operating_units hou, ap_suppliers asu, ap_supplier_sites_all assa, ap_invoice_lines_all aila WHERE
hou.organization_id = aia.org_id AND aia.vendor_id = asu.vendor_id AND aia.vendor_id = assa.vendor_id AND aia.set_of_books_id = hou.set_of_books_id AND aia.invoice_id = aila.invoice_id AND aia.invoice_id = :invoice_num and assa.vendor_site_id=aia.vendor_site_id;
